## Objective
Implement order API routes and WebSocket broadcasts.

## Files to write

### backend/routers/orders.py
```python
from fastapi import APIRouter, HTTPException, WebSocket, WebSocketDisconnect
from database import get_db, row_to_dict
from schemas import CreateOrder, StatusUpdate

router = APIRouter(prefix='/api', tags=['orders'])
admin_sockets = []
order_sockets = {}

def item_rows(db, order_id):
    rows = db.execute('SELECT * FROM order_items WHERE order_id=? ORDER BY id', (order_id,)).fetchall()
    return [row_to_dict(r) for r in rows]

def build_order(db, order_id):
    row = db.execute('SELECT * FROM orders WHERE id=?', (order_id,)).fetchone()
    if not row:
        return None
    data = row_to_dict(row)
    data['items'] = item_rows(db, order_id)
    return data

async def broadcast(order):
    dead = []
    for ws in admin_sockets:
        try:
            await ws.send_json(order)
        except Exception:
            dead.append(ws)
    for ws in dead:
        admin_sockets.remove(ws)
    for ws in list(order_sockets.get(order['id'], [])):
        try:
            await ws.send_json(order)
        except Exception:
            order_sockets[order['id']].remove(ws)

@router.get('/orders')
def list_orders(active_only: bool = False):
    db = get_db()
    where = " WHERE status!='picked_up'" if active_only else ''
    rows = db.execute('SELECT id FROM orders' + where + ' ORDER BY id DESC').fetchall()
    orders = [build_order(db, r['id']) for r in rows]
    db.close()
    return orders

@router.post('/orders')
async def create_order(data: CreateOrder):
    if not data.customer_name.strip() or not data.items:
        raise HTTPException(status_code=400, detail='Name and items required')
    db = get_db()
    settings = db.execute('SELECT is_open FROM settings WHERE id=1').fetchone()
    if settings and not settings['is_open']:
        db.close()
        raise HTTPException(status_code=400, detail='Cart is closed')
    next_id = db.execute('SELECT COALESCE(MAX(id),0)+1 n FROM orders').fetchone()['n']
    number = f'#{next_id:03d}'
    cur = db.execute('INSERT INTO orders (order_number,customer_name,status) VALUES (?,?,?)', (number,data.customer_name.strip(),'received'))
    order_id = cur.lastrowid
    for line in data.items:
        item = db.execute('SELECT * FROM menu_items WHERE id=? AND available=1', (line.item_id,)).fetchone()
        if not item or line.quantity < 1:
            db.rollback(); db.close(); raise HTTPException(status_code=400, detail='Invalid item')
        db.execute('''INSERT INTO order_items (order_id,item_id,item_name,item_price,quantity)
        VALUES (?,?,?,?,?)''', (order_id,item['id'],item['name'],item['price'],line.quantity))
    db.commit()
    order = build_order(db, order_id)
    db.close()
    await broadcast(order)
    return order

@router.get('/orders/{order_id}')
def get_order(order_id: int):
    db = get_db()
    order = build_order(db, order_id)
    db.close()
    if not order:
        raise HTTPException(status_code=404, detail='Order not found')
    return order

@router.patch('/orders/{order_id}/status')
async def update_status(order_id: int, data: StatusUpdate):
    if data.status not in ['received','in_progress','ready','picked_up']:
        raise HTTPException(status_code=400, detail='Invalid status')
    db = get_db()
    db.execute('UPDATE orders SET status=?, updated_at=CURRENT_TIMESTAMP WHERE id=?', (data.status,order_id))
    db.commit()
    order = build_order(db, order_id)
    db.close()
    if not order:
        raise HTTPException(status_code=404, detail='Order not found')
    await broadcast(order)
    return order

@router.websocket('/ws/admin')
async def ws_admin(ws: WebSocket):
    await ws.accept(); admin_sockets.append(ws)
    try:
        while True: await ws.receive_text()
    except WebSocketDisconnect:
        if ws in admin_sockets: admin_sockets.remove(ws)

@router.websocket('/ws/orders/{order_id}')
async def ws_order(ws: WebSocket, order_id: int):
    await ws.accept(); order_sockets.setdefault(order_id, []).append(ws)
    try:
        while True: await ws.receive_text()
    except WebSocketDisconnect:
        if ws in order_sockets.get(order_id, []): order_sockets[order_id].remove(ws)
```

## Objective
Create global cart state with localStorage persistence.

## Files to write

### frontend/src/context/CartContext.tsx
```tsx
import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { CartLine, MenuItem } from '../types';

type CartContextValue = {
  lines: CartLine[];
  count: number;
  subtotal: number;
  addItem: (item: MenuItem, quantity?: number) => void;
  setQuantity: (itemId: number, quantity: number) => void;
  removeItem: (itemId: number) => void;
  clear: () => void;
};

const CartContext = createContext<CartContextValue | undefined>(undefined);

export function CartProvider({ children }: { children: React.ReactNode }) {
  const [lines, setLines] = useState<CartLine[]>(() => {
    try { return JSON.parse(localStorage.getItem('foodcart_cart') || '[]'); } catch { return []; }
  });
  useEffect(() => { localStorage.setItem('foodcart_cart', JSON.stringify(lines)); }, [lines]);
  const addItem = (item: MenuItem, quantity = 1) => setLines(prev => {
    const existing = prev.find(l => l.item.id === item.id);
    if (existing) return prev.map(l => l.item.id === item.id ? { ...l, quantity: l.quantity + quantity } : l);
    return [...prev, { item, quantity }];
  });
  const setQuantity = (itemId: number, quantity: number) => setLines(prev => quantity < 1 ? prev.filter(l => l.item.id !== itemId) : prev.map(l => l.item.id === itemId ? { ...l, quantity } : l));
  const removeItem = (itemId: number) => setLines(prev => prev.filter(l => l.item.id !== itemId));
  const clear = () => setLines([]);
  const value = useMemo(() => ({
    lines,
    count: lines.reduce((s, l) => s + l.quantity, 0),
    subtotal: lines.reduce((s, l) => s + l.quantity * l.item.price, 0),
    addItem, setQuantity, removeItem, clear
  }), [lines]);
  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
}

export function useCart() {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error('useCart must be used inside CartProvider');
  return ctx;
}
```

