  const [form, setForm] = useState({ name:'', description:'', price:'0', category_id:1, photo_url:'', available:true, sort_order:0 });
  useEffect(() => { fetch('/api/categories').then(r=>r.json()).then(c => { setCats(c); if (c[0]) setForm(f => ({ ...f, category_id: c[0].id })); }); if (id && id !== 'new') fetch(`/api/menu/${id}`).then(r=>r.json()).then((m: MenuItem) => setForm({ ...m, price: String(m.price) })); }, [id]);
  async function upload(file: File) { const fd = new FormData(); fd.append('file', file); const res = await fetch('/api/uploads', { method: 'POST', body: fd }); const data = await res.json(); setForm(f => ({ ...f, photo_url: data.url })); }
  async function save() { const body = { ...form, price: Number(form.price), category_id: Number(form.category_id), sort_order: Number(form.sort_order) }; await fetch(id && id !== 'new' ? `/api/menu/${id}` : '/api/menu', { method: id && id !== 'new' ? 'PATCH' : 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }); nav('/admin/menu'); }
  const input = (k: string, v: any) => setForm(f => ({ ...f, [k]: v }));
